import math
import sys
import unittest
from pathlib import Path

sys.path.insert(0, str(Path(__file__).parents[1] / "src"))

from parcel_counter import shipping_price


class ShippingPriceTests(unittest.TestCase):
    def test_light_parcel(self) -> None:
        self.assertEqual(shipping_price(0.5), 5)

    def test_five_kg_uses_standard_band(self) -> None:
        self.assertEqual(shipping_price(5), 8)

    def test_heavy_parcel(self) -> None:
        self.assertEqual(shipping_price(5.01), 12)

    def test_negative_weight_is_rejected(self) -> None:
        with self.assertRaises(ValueError):
            shipping_price(-0.1)

    def test_non_finite_weight_is_rejected(self) -> None:
        with self.assertRaises(ValueError):
            shipping_price(math.inf)

